const { username, password } = $('Preparar Login').first().json;
const rows = ($input.all() || []).map(i => i.json).filter(u => u && u.id);
const user = rows[0] || null;

let ok = false;
if (user && user.password_hash) {
  try { ok = verifyPbkdf2(password, user.password_hash); } catch (_) { ok = false; }
}

if (!ok) {
  return [{ json: { success: false, error: 'Credenciales incorrectas' } }];
}

let permisos = [];
try {
  permisos = Array.isArray(user.permisos) ? user.permisos
           : typeof user.permisos === 'string' ? JSON.parse(user.permisos) : [];
} catch (_) { permisos = []; }

// Token opaco: 128 bits aleatorios en hex (no necesita crypto-grade; es
// sólo un identificador de sesión).
function genToken(){const b=new Uint8Array(16);for(let i=0;i<16;i++)b[i]=Math.floor(Math.random()*256);return Array.from(b).map(x=>x.toString(16).padStart(2,'0')).join('');}
const token = genToken();

return [{
  json: {
    success: true,
    token,
    user: {
      id:                   user.id,
      username:             user.username,
      nombre:               user.nombre || user.username,
      email:                user.email || '',
      rol:                  user.rol || 'user',
      permisos:             permisos,
      sessions_revoked_at:  user.sessions_revoked_at || null
    },
    _internal: { userId: user.id }
  }
}];

// Limpia _internal antes de devolver al cliente
const j = $('Verificar password').first().json;
return [{ json: { success: j.success, token: j.token, user: j.user } }];

// Devuelve el estado actual del usuario para que el frontend valide si
// la sesión guardada sigue siendo fresca. Campos sensibles (password_hash)
// nunca se exponen.
const q = ($input.first().json && $input.first().json.query) || {};
const userId = String(q.userId || q.id || '').trim();
if (!userId) throw new Error('userId requerido en query');
return [{ json: { userId } }];

// Respuesta del verify: el frontend la compara con la sesión local.
// - ok: true si hay usuario activo y no borrado
// - sessions_revoked_at: timestamp del último evento que invalida sesiones
// - rol + permisos: para que el frontend refresque si cambiaron sin re-login
function parseJson(v, fb){if(v==null)return fb;if(Array.isArray(v)||typeof v==='object')return v;if(typeof v==='string'){try{return JSON.parse(v);}catch(_){return fb;}}return fb;}
const rows = ($input.all() || []).map(i => i.json).filter(u => u && u.id);
const u = rows[0];
if (!u || u.deleted_at || u.activo === false) {
  return [{ json: { ok: false, reason: 'usuario inactivo o no encontrado' } }];
}
return [{ json: {
  ok: true,
  sessions_revoked_at: u.sessions_revoked_at || null,
  rol: u.rol || 'user',
  permisos: parseJson(u.permisos, []),
  activo: !!u.activo
}}];

// Saneo y sin exponer password_hash jamás.
function parseJsonField(v, fb) {
  if (v == null) return fb;
  if (Array.isArray(v) || typeof v === 'object') return v;
  if (typeof v === 'string') { try { return JSON.parse(v); } catch (_) { return fb; } }
  return fb;
}
const rows = $input.all().map(i => i.json).filter(u => u && u.id);
