const body = ($input.first().json.body) || {};
const action = String(body.action || '').toLowerCase();
const u = body.usuario || {};

if (!['create','update','delete','password'].includes(action)) {
  throw new Error('action requerida: create | update | delete | password');
}

const PERMISOS_VALIDOS = new Set(['ventas','distribucion','lista','bajas','sinasignar','proyectos','contabilidad','clientes','integraciones','admin','docs']);
const PASSWORD_MIN_LEN = 8;

function validarPermisosEstricto(arr) {
  if (arr == null) return [];
  if (!Array.isArray(arr)) throw new Error('permisos debe ser un array');
  const invalidos = arr.filter(p => !PERMISOS_VALIDOS.has(String(p)));
  if (invalidos.length > 0) {
    throw new Error('Permisos inválidos: ' + invalidos.join(', '));
  }
  return arr.map(String);
}
function validarPasswordLen(pw) {
  if (typeof pw !== 'string' || pw.length < PASSWORD_MIN_LEN) {
    throw new Error('La contraseña debe tener al menos ' + PASSWORD_MIN_LEN + ' caracteres');
  }
}

// Marca de tiempo de "sesiones revocadas": cada vez que cambian
// permisos/rol/activo o se borra un usuario, actualizamos sessions_revoked_at
// para que las sesiones activas se invaliden (el front comprueba este campo
// periódicamente contra la sesión local).
const nowIso = new Date().toISOString();

let payload = null;

if (action === 'create') {
  if (!u.username || !u.password) throw new Error('username y password son obligatorios');
  validarPasswordLen(u.password);
  payload = {
    username: String(u.username).trim().toLowerCase(),
    password_hash: hashPassword(String(u.password)),
    nombre: u.nombre ? String(u.nombre).trim() : null,
    email: u.email ? String(u.email).trim().toLowerCase() : null,
    rol: u.rol === 'admin' ? 'admin' : 'user',
    permisos: JSON.stringify(validarPermisosEstricto(u.permisos)),
    activo: u.activo !== false
  };
} else if (action === 'update') {
  if (!u.id) throw new Error('Falta id para update');
  payload = { id: u.id };
  let tocaSesion = false;
  if (u.nombre !== undefined)   payload.nombre   = u.nombre ? String(u.nombre).trim() : null;
  if (u.email  !== undefined)   payload.email    = u.email  ? String(u.email).trim().toLowerCase() : null;
  if (u.rol    !== undefined)   { payload.rol = u.rol === 'admin' ? 'admin' : 'user'; tocaSesion = true; }
  if (u.permisos !== undefined) { payload.permisos = JSON.stringify(validarPermisosEstricto(u.permisos)); tocaSesion = true; }
  if (u.activo !== undefined)   { payload.activo = !!u.activo; tocaSesion = true; }
  if (tocaSesion) payload.sessions_revoked_at = nowIso;
} else if (action === 'password') {
  if (!u.id || !u.password) throw new Error('Falta id o password para cambio de password');
  validarPasswordLen(u.password);
  // Cambiar password también invalida sesiones (por si alguien comprometido)
  payload = { id: u.id, password_hash: hashPassword(String(u.password)), sessions_revoked_at: nowIso };
} else if (action === 'delete') {
  if (!u.id) throw new Error('Falta id para delete');
  payload = { id: u.id, deleted_at: nowIso, activo: false, sessions_revoked_at: nowIso };
}

return [{ json: { action, payload } }];

// Aplana: el item que llega a HTTP Request tiene que ser DIRECTAMENTE
// el payload (id + columnas a actualizar). Además validamos que no se
// cuele username ni password_hash — esos NUNCA deben cambiar desde el
// path de 'update'. Si estuvieran, los filtramos en vez de dejar que
// lleguen a la PATCH y arrastren NULL a una columna NOT NULL.
const payload = $input.first().json.payload || {};
const { username, password_hash, ...safePayload } = payload;
if (!safePayload.id) throw new Error('Falta id en payload de UPDATE');
return [{ json: safePayload }];

// Construye el body de la PATCH de forma explícita. Antes usábamos una
// expresión en jsonBody con IIFE y spread, que en versiones concretas de
// n8n (self-hosted) puede fallar o evaluar a algo distinto de lo
// esperado — causó un 'null value in column username' pese a no incluir
// username en el payload. Aquí el cuerpo se construye en JS sin
// dependencia de expresiones complejas y se guarda en $json.__body para
// que la HTTP Request lo consuma tal cual.
const j = $input.first().json || {};
const body = { ...j };
delete body.id;
// Eliminar claves que nunca deben ir en PATCH (defensivo)
delete body.username;
delete body.password_hash;
return [{ json: { id: j.id, __body: JSON.stringify(body) } }];

// Construye respuesta consistente {success, action, affected, errores, usuario}
// sin exponer nunca password_hash.
const { action } = $('Preparar acción Usuario').first().json;
const input = $input.all();
let count = 0;
const errores = [];
let usuario = null;

for (const it of (input || [])) {
  const j = (it && it.json) ? it.json : it;
  if (!j) continue;
  if (j.error) {
    errores.push(String(j.error.message || j.error.code || j.error));
    continue;
  }
  if (j.code && j.message && !j.id) {
    errores.push(j.message + (j.details ? ' (' + j.details + ')' : ''));
    continue;
  }
  if (Array.isArray(j)) {
    count += j.length;
    if (!usuario && j.length > 0) usuario = j[0];
    continue;
  }
  if (j.id) { count++; if (!usuario) usuario = j; continue; }
}
if (usuario) delete usuario.password_hash;
return [{ json: { success: count > 0, action, affected: count, errores, usuario } }];
